def a(n):
    squares = [k*k for k in range(1, n+1)]
    dp = [n+1] * (n**3 + 2)
    dp[0] = 0
    for s in squares:
        for v in range(s, n**3 + 2):
            if dp[v-s] + 1 < dp[v]:
                dp[v] = dp[v-s] + 1
    result = 0
    for v in range(1, n**3 + 2):
        if dp[v] <= n: result = v
        else: break
    return result

